css:
* { margin: 0; padding: 0; box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; }
body { background: #f7f4ef; color: #2e2a25; }
.navbar { display: flex; align-items: center; justify-content: space-between; padding: 24px 60px; }
.brand { font-size: 20px; font-weight: 900; letter-spacing: 0.1em; }
.nav-links { display: flex; gap: 28px; }
.nav-links a { color: #a39c8f; text-decoration: none; font-size: 14px; font-weight: 600; }
.nav-links a.active { color: #2e2a25; }
.cart-icon { font-size: 15px; font-weight: 700; cursor: pointer; }
.hero { padding: 60px; background: linear-gradient(135deg, #efe8dc, #f7f4ef); }
.hero-text { max-width: 560px; }
.badge { display: inline-block; color: #a16207; font-size: 12px; font-weight: 800; letter-spacing: 0.18em; margin-bottom: 22px; }
.hero h1 { font-size: 48px; font-weight: 800; line-height: 1.3; margin-bottom: 18px; }
.hero h1 span { color: #a16207; }
.hero p { color: #a39c8f; font-size: 15px; line-height: 1.8; margin-bottom: 28px; }
.btn-primary { background: #2e2a25; color: white; border: none; padding: 15px 32px; font-size: 13.5px; font-weight: 700; cursor: pointer; border-radius: 4px; }
.products { padding: 50px 60px; }
.filter-row { display: flex; gap: 10px; margin-bottom: 30px; flex-wrap: wrap; }
.filter { background: white; border: 1px solid #ece4d8; color: #a39c8f; padding: 9px 18px; border-radius: 999px; font-size: 13px; font-weight: 700; cursor: pointer; }
.filter.active { background: #2e2a25; color: white; border-color: #2e2a25; }
.product-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(220px, 1fr)); gap: 24px; }
.product-card { cursor: pointer; }
.product-img { aspect-ratio: 1; background: white; border-radius: 14px; display: flex; align-items: center; justify-content: center; font-size: 56px; margin-bottom: 14px; transition: 0.2s; box-shadow: 0 8px 24px rgba(0,0,0,0.04); }
.product-card:hover .product-img { transform: translateY(-4px); }
.cat-label { display: block; font-size: 11.5px; color: #c9a96e; text-transform: uppercase; letter-spacing: 0.05em; font-weight: 700; margin-bottom: 6px; }
.product-card h3 { font-size: 15px; font-weight: 700; margin-bottom: 4px; }
.price { color: #2e2a25; font-weight: 800; font-size: 14px; }
.cart-drawer { position: fixed; top: 0; right: -380px; width: 360px; height: 100%; background: white; box-shadow: -10px 0 40px rgba(0,0,0,0.1); z-index: 20; transition: right 0.3s; display: flex; flex-direction: column; }
.cart-drawer.open { right: 0; }
.cart-header { display: flex; justify-content: space-between; align-items: center; padding: 24px; border-bottom: 1px solid #ece4d8; }
.cart-header h2 { font-size: 18px; font-weight: 800; }
.cart-header button { background: none; border: none; font-size: 18px; cursor: pointer; }
.cart-items { flex: 1; overflow-y: auto; padding: 16px 24px; display: flex; flex-direction: column; gap: 14px; }
.cart-item { display: flex; gap: 14px; align-items: center; }
.cart-item-img { width: 56px; height: 56px; background: #f7f4ef; border-radius: 12px; display: flex; align-items: center; justify-content: center; font-size: 24px; flex-shrink: 0; }
.cart-item-info { flex: 1; }
.cart-item-info h4 { font-size: 13.5px; font-weight: 700; }
.cart-item-info span { font-size: 12.5px; color: #a39c8f; }
.remove-btn { background: none; border: none; color: #ccc; font-size: 14px; cursor: pointer; }
.cart-footer { padding: 24px; border-top: 1px solid #ece4d8; }
.cart-total { display: flex; justify-content: space-between; font-size: 16px; font-weight: 800; margin-bottom: 16px; }
.btn-primary.full { width: 100%; padding: 15px; }
.overlay { position: fixed; inset: 0; background: rgba(0,0,0,0.3); display: none; z-index: 19; }
.overlay.show { display: block; }
@media (max-width: 900px) { .navbar, .hero, .products { padding-left: 24px; padding-right: 24px; } .nav-links { display: none; } .hero h1 { font-size: 32px; } .cart-drawer { width: 100%; right: -100%; } }

