const products = [
  { id: 1, name: 'Bouclé Üç Kişilik Koltuk', cat: 'living', label: 'Oturma Odası', price: 18900, emoji: '🛋️' },
  { id: 2, name: 'Ahşap Yatak Başlığı', cat: 'bedroom', label: 'Yatak Odası', price: 7200, emoji: '🛏️' },
  { id: 3, name: 'Ergonomik Çalışma Sandalyesi', cat: 'office', label: 'Ofis', price: 5400, emoji: '🪑' },
  { id: 4, name: 'Sehpa - Meşe', cat: 'living', label: 'Oturma Odası', price: 3200, emoji: '🪵' },
  { id: 5, name: 'Komodin Seti', cat: 'bedroom', label: 'Yatak Odası', price: 4100, emoji: '🗄️' },
  { id: 6, name: 'Yükseklik Ayarlı Masa', cat: 'office', label: 'Ofis', price: 8900, emoji: '🖥️' },
  { id: 7, name: 'Halı - Bej Desenli', cat: 'living', label: 'Oturma Odası', price: 2800, emoji: '🧶' },
  { id: 8, name: 'Kitaplık - 5 Raflı', cat: 'office', label: 'Ofis', price: 3600, emoji: '📚' }
];

let cart = [];

function renderProducts(filter) {
  const grid = document.getElementById('productGrid');
  grid.innerHTML = '';
  products
    .filter(p => filter === 'all' || p.cat === filter)
    .forEach(p => {
      const card = document.createElement('div');
      card.className = 'product-card';
      card.innerHTML = `
        <div class="product-img">${p.emoji}</div>
        <span class="cat-label">${p.label}</span>
        <h3>${p.name}</h3>
        <span class="price">₺${p.price.toLocaleString('tr-TR')}</span>
      `;
      card.addEventListener('click', () => addToCart(p));
      grid.appendChild(card);
    });
}

function filterProducts(btn, filter) {
  document.querySelectorAll('.filter').forEach(f => f.classList.remove('active'));
  btn.classList.add('active');
  renderProducts(filter);
}

function addToCart(product) {
  cart.push(product);
  updateCart();
  toggleCart(true);
}

function removeFromCart(index) {
  cart.splice(index, 1);
  updateCart();
}

function updateCart() {
  document.getElementById('cartCount').textContent = cart.length;
  const itemsContainer = document.getElementById('cartItems');
  itemsContainer.innerHTML = '';
  let total = 0;
  cart.forEach((item, i) => {
    total += item.price;
    const div = document.createElement('div');
    div.className = 'cart-item';
    div.innerHTML = `
      <div class="cart-item-img">${item.emoji}</div>
      <div class="cart-item-info"><h4>${item.name}</h4><span>₺${item.price.toLocaleString('tr-TR')}</span></div>
      <button class="remove-btn" onclick="removeFromCart(${i})">✕</button>
    `;
    itemsContainer.appendChild(div);
  });
  document.getElementById('cartTotal').textContent = `₺${total.toLocaleString('tr-TR')}`;
}

function toggleCart(forceOpen) {
  const drawer = document.getElementById('cartDrawer');
  const overlay = document.getElementById('overlay');
  const shouldOpen = forceOpen !== undefined ? forceOpen : !drawer.classList.contains('open');
  drawer.classList.toggle('open', shouldOpen);
  overlay.classList.toggle('show', shouldOpen);
}

renderProducts('all');
